#include<stdio.h>
int a[100001];
int bs(int n,int x){int l=0,r=n-1;while(l<=r){int m=(l+r)/2;if(a[m]==x)return 1;if(a[m]<x)l=m+1;else r=m-1;}return 0;}
int main(){int n,q;scanf("%d %d",&n,&q);for(int i=0;i<n;i++)scanf("%d",&a[i]);while(q--){int x;scanf("%d",&x);puts(bs(n,x)?"YES":"NO");}}
